export async function gerarPdfOrcamentoFront(orcamento: IOrcamentoForm) {
  const element = document.createElement("div");
  element.innerHTML = gerarHtmlOrcamento(orcamento);

  html2pdf()
    .from(element)
    .set({
      margin: 10,
      filename: `${orcamento.nomeDoArquivo ? orcamento.nomeDoArquivo : "orçamento"}.pdf`,
      html2canvas: { scale: 2 },
      jsPDF: {
        unit: "mm",
        format: "a4",
        orientation: "portrait",
      },
    })
    .save();
}

export async function createOrcamento(orcamento: ICreateOrcamento) {
  return await httpClient("/orcamento", {
    method: "POST",
    body: JSON.stringify(orcamento),
  });
}
